using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// [.NET 9 fix] Changed from Singleton to Scoped — a singleton factory calling
// GetRequiredService<IUserService>() captures a scoped service, which now throws
// at startup because ValidateScopes is enabled by default in development.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// [.NET 9 fix] Replaced ConfigureHttpMessageHandlerBuilder + HttpClientHandler cast.
// The default primary handler is now SocketsHttpHandler; the old cast throws
// InvalidCastException. ConfigurePrimaryHttpMessageHandler also resolves the
// pre-existing CS0618 obsolete-API warning.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });
// [.NET 9 fix] Allowlist non-sensitive headers for Trace-level logging.
// HttpClientFactory now redacts all header values by default; without this,
// Trace-level header debugging shows only redacted placeholders.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        !string.Equals(h, "X-Request-Id", StringComparison.OrdinalIgnoreCase) &&
        !string.Equals(h, "X-Forwarded-For", StringComparison.OrdinalIgnoreCase)));
// [.NET 9 fix] ForwardedHeadersMiddleware now ignores X-Forwarded-* headers
// from proxies not in KnownProxies/KnownNetworks. Add your reverse proxy
// address here, or forwarded headers will be silently dropped.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

